  ('locality-7c9828ae-moex-00095', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依行政罰法規定，關於責任能力之敘述，下列何者錯誤？', '["未滿14歲人之行為，不予處罰", "14歲以上未滿18歲人之行為，得減輕處罰", "行為時因精神障礙或其他心智缺陷，致不能辨識其行為違法者，得依情節輕重不予處罰或減輕處罰", "行為時因精神障礙或其他心智缺陷，致依其辨識而行為之能力，顯著減低者，得減輕處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00096', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '對法人違反行政法上義務為處罰，關於其責任條件之要求與認定方式，下列敘述何者正確？', '["毋須論故意、過失", "只罰故意違法行為", "其代表人、管理人或其他各類職員之故意或過失，視為該法人之故意、過失", "其代表人、管理人或其他各類職員之故意或過失，推定為該法人之故意、過失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00097', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '有關行政命令對於法官之拘束，下列敘述何者正確？', '["法官應受行政機關依職權所訂定職權命令的拘束", "法官應受上級行政機關授權下級行政機關所訂定命令的拘束", "法官應受行政機關依職權所訂定行政規則的拘束", "各機關依職掌就有關法規所為釋示之命令，法官不受拘束"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00098', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '行政機關於裁處行政罰前，如個案情節符合法定要件，得不給予受處罰者陳述意見之機會。下列何者非屬 前述法定要件？', '["已依行政程序法給予陳述意見機會", "情況急迫，給予陳述意見機會將有害公益", "受法定期間之限制，給予陳述意見機會將無法遵守時效", "行為人多次違反相同之行政法上義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00099', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '違反行政法上義務之人死亡後，是否得對其科處罰鍰與強制執行，下列敘述何者正確？', '["行為人於違規行為時點後死亡，仍應作成科處罰鍰之處分", "若作成罰鍰處分後行為人死亡，得對其繼承人重為罰鍰處分", "若作成罰鍰處分後行為人死亡，得對受處分人之遺產強制執行", "若作成罰鍰處分後行為人死亡，罰鍰繳納義務由繼承人繼承，得對繼承人之固有財產強制執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00100', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '下列何者屬於行政執行之間接強制手段？', '["怠金", "拆除住宅", "註銷證照", "斷水斷電"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00101', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依行政執行法規定，有關即時強制之敘述，下列何者正確？', '["進入住宅應先聲請法院核發搜索票", "對於執行機關所為損失補償決定不服者，為求經濟，不須經過訴願程序，得逕行向民事法院提起國家賠 償訴訟", "員警為避免當事人持續鬥毆，將其管束於警局內24小時，始恢復其自由", "對於危險物品之扣留，應得檢察官之許可方得為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00102', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '動物保育團體甲向主管機關乙請求交付乙持有A公司申請引進展示外國保育類野生動物營業秘密資訊， 以及乙內部許可A引進展示審查會議紀錄，皆遭駁回。乙下列處置何者錯誤？', '["A申請引進之展示資訊涉及A營業秘密，乙不得任意公開", "A申請引進展示之資訊經其同意後，乙得予公開", "乙內部審查會議紀錄屬擬稿或其他準備作業，得不公開", "甲請求資訊部分涉及營業秘密，乙仍應拒絕全部請求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00103', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '依行政程序法規定，行政機關作成限制或剝奪人民自由或權利之行政處分前，原則上應給予該處分相對人 陳述意見之機會，但遇有例外情形者不在此限。下列何者不該當於此等例外情形？', '["行政處分所根據之事實，客觀上明白足以確認者", "大量作成同種類之處分", "為避免業務上之負擔，得不給予陳述意見之機會", "避免處分相對人潛逃出境，依法律所為限制出境之處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL),
  ('locality-7c9828ae-moex-00104', 'locality-7c9828ae', 'locality-7c9828ae-moex-113-d1a761c9', 'sub-locality-7c9828ae-03', NULL, 'single_choice', '關於行政程序法期間規定之敘述，下列何者正確？', '["人民於法定期間內提出申請，經移送有管轄權之機關者，須再次提出申請", "期間之末日為星期六者，以其次星期一下午為期間末日", "申請人因不諳法令，不能於法定期間內提出申請，得申請回復原狀", "除法規另有規定外，行政機關應訂定人民申請之處理期間 3601"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:07+00:00", "source_pdf_sha1": "94200c541a8b", "answer_pdf_sha1": "f7c4c256beb5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "407", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "社會工作"}'::jsonb, NULL)
